import{_ as a,o as r,c as t,a5 as l}from"./chunks/framework.B5tqjWbr.js";const P=JSON.parse('{"title":"学习记录 #0007：单相PFC整流器——从整流到功率因数校正","description":"","frontmatter":{"date":"2026-06-14T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"学习记录 #0007：单相PFC整流器——从整流到功率因数校正","tags":["power-electronics"],"status":"learning","summary":"**日期**：2026-06-13 **课程**：第7课 — 单相PFC整流器（Phase 2核心拓扑开始） **状态**：进行中"},"headers":[],"relativePath":"content/power/archive/old-learning-records/0007-single-phase-pfc.md","filePath":"content/power/archive/old-learning-records/0007-single-phase-pfc.md","lastUpdated":null}'),o={name:"content/power/archive/old-learning-records/0007-single-phase-pfc.md"};function i(n,e,s,c,d,h){return r(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="学习记录-0007-单相pfc整流器——从整流到功率因数校正" tabindex="-1">学习记录 #0007：单相PFC整流器——从整流到功率因数校正 <a class="header-anchor" href="#学习记录-0007-单相pfc整流器——从整流到功率因数校正" aria-label="Permalink to &quot;学习记录 #0007：单相PFC整流器——从整流到功率因数校正&quot;">​</a></h1><p><strong>日期</strong>：2026-06-13 <strong>课程</strong>：第7课 — 单相PFC整流器（Phase 2核心拓扑开始） <strong>状态</strong>：进行中</p><h2 id="关键洞察" tabindex="-1">关键洞察 <a class="header-anchor" href="#关键洞察" aria-label="Permalink to &quot;关键洞察&quot;">​</a></h2><ol><li><strong>PFC目标</strong>：PF&gt;0.99，THD&lt;5%，满足IEC 61000-3-2谐波标准</li><li><strong>双闭环结构</strong>：电压外环（10~20Hz慢环）+ 电流内环（2~5kHz快环）</li><li><strong>电流参考生成</strong>：Iref = A × Vac / V²rms，V²rms前馈消除输入电压变化影响</li><li><strong>电压环低带宽原因</strong>：输出电压含100Hz纹波，带宽过高会将纹波耦合到电流参考→3次谐波→THD恶化</li><li><strong>非线性PI</strong>：误差小用小增益（低THD），误差大用大增益（快速恢复），解耦两个矛盾需求</li><li><strong>占空比前馈</strong>：dFF = 1 - Vin/Vout，PI只需补偿动态误差，大幅提高跟踪速度</li><li><strong>V²rms计算</strong>：滑动窗口法，1300点环形缓冲区，每PWM周期更新</li></ol><h2 id="代码要点" tabindex="-1">代码要点 <a class="header-anchor" href="#代码要点" aria-label="Permalink to &quot;代码要点&quot;">​</a></h2><ul><li>V²rms滑动窗口：环形缓冲区+累加和，O(1)复杂度</li><li>非线性PI：根据误差大小切换Kp/Ki</li><li>完整PFC控制：采样→V²rms→电压环→Iref生成→电流环→前馈→PWM</li></ul><h2 id="待深入问题" tabindex="-1">待深入问题 <a class="header-anchor" href="#待深入问题" aria-label="Permalink to &quot;待深入问题&quot;">​</a></h2><ul><li>[ ] Totem-Pole无桥PFC的双向电流采样怎么处理？</li><li>[ ] CRM模式PFC的恒定Ton法原理？</li><li>[ ] 交错PFC的均流控制？</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>进入第8课：维也纳整流器（三相PFC）</p>',10)])])}const p=a(o,[["render",i]]);export{P as __pageData,p as default};
